public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    Character quoteChar = null;

    do {
        if (isEmpty()) break;
        Character c = consume();
        if (last == 0 || last != ESC) {
            if (quoteChar == null && (c.equals('\'') || c.equals('"')) && c != open) {
                quoteChar = c;
            } else if (quoteChar != null && c.equals(quoteChar)) {
                quoteChar = null;
            }
            if (quoteChar == null) {
                if (c.equals(open)) {
                    depth++;
                    if (start == -1)
                        start = pos;
                }
                else if (c.equals(close))
                    depth--;
            }
        }

        if (depth > 0 && last != 0)
            end = pos;
        last = c;
    } while (depth > 0);
    final String out = (end >= 0) ? queue.substring(start, end) : "";
    return out;
}

public static Evaluator parse(String query) {
    QueryParser p = new QueryParser(query);
    return p.parse();
}

